CREATE OR REPLACE FUNCTION f_get_shr_receipt_no ( as_recetip_no text ) RETURNS bigint AS $body$
DECLARE

    ldc_balance bigint;

BEGIN
    ldc_balance := 0;


    select coalesce(balance,0) into STRICT  ldc_balance
    from sc_com_m_receipt_item
    where trim(both receipt_no) = trim(both as_recetip_no)
    and item_type_id = 'SB';

    if coalesce(ldc_balance::text, '') = '' then ldc_balance := 0;end if;


  RETURN coalesce(ldc_balance,0);

  
END;
$body$
LANGUAGE PLPGSQL
